import{_ as o,o as a,c as t,a1 as s}from"./chunks/framework.Cgy8VYHZ.js";const u=JSON.parse('{"title":"过程的压缩","description":"","frontmatter":{"title":"过程的压缩","customTag":"blog>AIGC","date":"2026-01-24T00:00:00.000Z","editLink":true},"headers":[],"relativePath":"blog/process-compression.md","filePath":"blog/process-compression.md","lastUpdated":1773500785000}'),r={name:"blog/process-compression.md"};function e(l,p,n,g,i,c){return a(),t("div",null,[...p[0]||(p[0]=[s('<h1 id="过程的压缩" tabindex="-1">过程的压缩 <a class="header-anchor" href="#过程的压缩" aria-label="Permalink to &quot;过程的压缩&quot;">​</a></h1><p>2025 年 AI 应用层发展是较快的，</p><p>市面有越来越多的工具出现。</p><p>在我个人的生活和工作中，</p><p>AI 也确实能够提高不少的效率。</p><p><strong>但在 AI 工具加持下，</strong></p><p><strong>我总觉得少了些什么？</strong></p><p>如果现在大模型的主题是**“压缩”**，</p><p>那么实际上我越来越感觉到，</p><p>我正在经历一场**“过程的压缩/消失”，**</p><p>但目前我还不好评判其利弊。</p><p><img src="https://llm-1258926018.cos.ap-guangzhou.myqcloud.com/uploads/1766812603382-generated-1766812603382-131fdcu24ezb.png" alt="图片-1"></p><h2 id="现象" tabindex="-1">现象 <a class="header-anchor" href="#现象" aria-label="Permalink to &quot;现象&quot;">​</a></h2><p>作为信息爱好者和 AI 爱好者，</p><p>在过去三年中，</p><p>我的日常是，</p><ul><li><p>收集 AI 领域信息</p></li><li><p>使用 AI 工具</p></li><li><p>做 AI 应用、工程。</p></li></ul><p>而我也确实很享受这个过程，</p><p>但在今年开头的时候，</p><p>我突然感觉我对这过程陌生了。</p><p>从近期我自己的几个场景来说起吧。</p><h3 id="模糊-的正确" tabindex="-1">“模糊”的正确 <a class="header-anchor" href="#模糊-的正确" aria-label="Permalink to &quot;“模糊”的正确&quot;">​</a></h3><p>近期由于工作上的需求，</p><p>需要了解“机器学习”中“序列”的信息。</p><p>由于个人未曾从事该领域，</p><p>在一开始的时候遇到了下方问题</p><ul><li><p>内部文档很多术语听不懂</p></li><li><p>和对应算法同学沟通概念对不齐</p></li><li><p>无法具体的工作是如何串起来的</p></li></ul><p>我也尝试用 Deep Research 的能力，</p><p>让不同的 AI 帮我去跑报告，</p><p>帮我做各种信息整合。</p><p>但不同的 AI 每次给的信息，</p><p>实际上都有些细节点上的不同。</p><p>但对比上方的细节点，我更不能分辨，</p><p>只能让 AI 再评判这些不同的细节。</p><p><img src="https://llm-1258926018.cos.ap-guangzhou.myqcloud.com/uploads/1769262361904-image.png" alt=""><img src="https://llm-1258926018.cos.ap-guangzhou.myqcloud.com/uploads/1769262326730-image.png" alt=""><img src="https://llm-1258926018.cos.ap-guangzhou.myqcloud.com/uploads/1769262209459-image.png" alt=""></p><p>虽然最后还是勉强地做了版个人梳理，</p><p>但我始终觉得，</p><p>目前我收集和理解到的，</p><p>只是大概理论，甚至有所偏差，</p><p>也就是所谓的锯齿状知识。</p><p>虽然理解上好了一点点，</p><p>抽象层面的概念和流程能对齐，</p><p>但细节上的点还是脑袋嗡嗡的。</p><p>在整个过程中，</p><p>貌似 AI 能够快速帮我们整合信息，</p><p>能够快速给我们<strong>一份结果的报告，</strong></p><p><strong>但这只是知识的一面，</strong></p><p><strong>也许很多隐形知识和细节更多在过程中。</strong></p><p><strong>需要警惕这种“模糊”的正确。</strong></p><p><img src="https://llm-1258926018.cos.ap-guangzhou.myqcloud.com/uploads/1769262624436-generated-1769262624436-583844xpr9.png" alt="图片-1"></p><h3 id="黑盒-的代码" tabindex="-1">“黑盒”的代码 <a class="header-anchor" href="#黑盒-的代码" aria-label="Permalink to &quot;“黑盒”的代码&quot;">​</a></h3><p>从去年下半年开始，</p><p>个人就在比较多使用 Coding Agent 工具。</p><p>一般用 Codex, Claude Code 会比较多，</p><p>但今年和去年的感觉十分不同。</p><p><img src="https://llm-1258926018.cos.ap-guangzhou.myqcloud.com/uploads/1769262782596-b2f4a3c690d2d9122a39ded899dba3cd.JPG" alt=""></p><p>去年的时候，</p><p>上半年 AI Coding 效果还没有那么好，</p><p>所以上半年还是手工写代码比较多，</p><p>但下半年开始，</p><p>AI 的能力提升，</p><p>让我将更多编码工作分配给 AI。</p><p><strong>可能是由于前期参与较多，</strong></p><p><strong>所以目前我还能够了解细节。</strong></p><p>而今年开始，</p><p>目前也在纯 Vibe Coding 一个项目，</p><p>大概 90% 代码是 AI 写的，</p><p>而我更多做需求下发和任务编排，</p><p>以及需要去补充下 AI 没处理好的地方。</p><p>这个项目进展还是比较快的，</p><p><strong>但我发现我已经把控不好这里面的细节。</strong></p><p>每次我要去修补些细节，</p><p>我甚至连代码文件都不太好找寻，</p><p>我已经理不清楚里面的数据逻辑。</p><p>总得来说，</p><p>最近让我越来越感觉，</p><p><strong>“黑盒的代码”。</strong></p><p><strong>虽然 AI Coding 貌似很交付结果，</strong></p><p><strong>但过程中失去太多本可把控的东西。</strong></p><p><img src="https://llm-1258926018.cos.ap-guangzhou.myqcloud.com/uploads/1769263113870-generated-1769263113870-572mxm8gn7.png" alt="图片-1"></p><h3 id="削弱-的耐心" tabindex="-1">“削弱”的耐心 <a class="header-anchor" href="#削弱-的耐心" aria-label="Permalink to &quot;“削弱”的耐心&quot;">​</a></h3><p>在过去几年的尝试下，</p><p>我貌似提高了效率，</p><p>但我失去的可能还有耐心。</p><p>当只用 DeepResearch,</p><p>就能得到一份质量还不错的报告总结，</p><p>当和 Coding Agent 对话，</p><p>就能得到一个所见即所得的产品功能。</p><p>当仅用自然语言交互，</p><p><strong>就可能得到那貌似正确但有模糊的答案。</strong></p><p>这是十分诱人的，</p><p>但一次一次获得的满足。</p><p>让我对缓慢而具体的过程，</p><p>更加没有耐心。</p><p>已经很久没有以前的一些感觉</p><ul><li><p>仔细阅读一篇优质文章</p></li><li><p>静下心来看完一本书</p></li><li><p>写代码/文章时候的心流状态</p></li></ul><p><img src="https://llm-1258926018.cos.ap-guangzhou.myqcloud.com/uploads/1769263113527-image.png" alt=""></p><p><strong>反而给我带来的是，</strong></p><p><strong>”日益增长“的注意力碎片化。</strong></p><h2 id="推测" tabindex="-1">推测 <a class="header-anchor" href="#推测" aria-label="Permalink to &quot;推测&quot;">​</a></h2><p>个人在近期也一直思考这些现象，</p><p>也在推测这些现象出现的原因。</p><h3 id="频率加速" tabindex="-1">频率加速 <a class="header-anchor" href="#频率加速" aria-label="Permalink to &quot;频率加速&quot;">​</a></h3><p>AI 作为一种新媒介，</p><p>我理解是让信息的频率变化。</p><p>当 AI 能帮你理解和生产内容，</p><p>你的信息消费/生产的频率变高了。</p><p>当 AI 能帮你做信息聚合和 AI Coding 的时候，</p><p>你短时间内要消耗的信息量也变多了，</p><p>信息接收频率也随之变高了。</p><p>当你既要在抽象层面去派活，</p><p>不用过多考虑细节的时候，</p><p>你的任务频率变高了。</p><p><strong>而当前的频率切换，</strong></p><p><strong>也许会让人没有更多精力深入细节。</strong></p><p><img src="https://llm-1258926018.cos.ap-guangzhou.myqcloud.com/uploads/1769263353358-generated-1769263353358-dtiejoehe7g.png" alt="图片-1"></p><h3 id="信息粒度的不匹配" tabindex="-1">信息粒度的不匹配 <a class="header-anchor" href="#信息粒度的不匹配" aria-label="Permalink to &quot;信息粒度的不匹配&quot;">​</a></h3><p>当我们将越来越多的任务交给了 AI，</p><p>而我们貌似只需要在抽象层面，</p><p>指明方向，做好设计，下发指令。</p><p><strong>我们想获得结果，</strong></p><p><strong>但是已经深入不了过程，</strong></p><p><strong>也无法了解过多的不了细节。</strong></p><p>这也就意味着，</p><p>我们通常只知道大概，</p><p>但我们想要处理细节的时候，</p><p><strong>天然就有信息粒度的对不齐。</strong></p><p>而这个时候，</p><p>也许你又得重新理解细节，</p><p>就好比从前，</p><p>你去维护未曾接触过的古老代码，</p><p>也许你会抗拒，</p><p>甚至你可能会觉得是种 dirty work.</p><p><img src="https://llm-1258926018.cos.ap-guangzhou.myqcloud.com/uploads/1769263383276-generated-1769263383276-meypafq8qsi.png" alt="图片-2"></p><h3 id="反馈循环" tabindex="-1">反馈循环 <a class="header-anchor" href="#反馈循环" aria-label="Permalink to &quot;反馈循环&quot;">​</a></h3><p>笔者一直觉得，</p><p>AI 作为媒介能给人带来反馈。</p><p>而其中带来的反馈，</p><p>就是那种**“更多注重结果”的反馈**。</p><p>**加深结果的正反馈：**当你能付出比较少的成本，获取一个具体的成果。</p><p>**理解细节的负反馈：**当你深入细节，发现需要付出过多的精力。</p><p>而当这两种反馈叠加，</p><p><strong>可能大多人会更喜欢结果，</strong></p><p><strong>而更不喜欢去了解过程吧。</strong></p><p><img src="https://llm-1258926018.cos.ap-guangzhou.myqcloud.com/uploads/1769263412070-generated-1769263412070-hngfmk4sos.png" alt="图片-3"></p><h2 id="把手弄脏" tabindex="-1">把手弄脏 <a class="header-anchor" href="#把手弄脏" aria-label="Permalink to &quot;把手弄脏&quot;">​</a></h2><p>貌似我通篇文章都在描述，</p><p>“不要追求结果，而要追求过程”。</p><p>但实际我并不想这么极端，</p><p>即使我是个偏追求过程的人。</p><p>我更多觉得是需要有些判断，</p><p>因地因时因场景地做判断，</p><p>看如何平衡好结果和过程。</p><p>同时，在你感兴趣、专业的领域上，</p><p>不要丢失动手，深入细节的能力。</p><p>把手弄脏，<strong>The journey is the reward.</strong></p><p><img src="https://llm-1258926018.cos.ap-guangzhou.myqcloud.com/uploads/1769263824397-generated-1769263824397-suihciq54jk.png" alt="图片-1"></p>',157)])])}const h=o(r,[["render",e]]);export{u as __pageData,h as default};
